column.value:
{
                "pageDescription": "Environmental Monitoring and Temperature Logging",
                "dataPoints": {
                    "temperatureLog": {
                        "deviceId": {
                            "type": "text",
                            "label": "Device/Equipment ID",
                            "required": true,
                            "example": "FRZ-001, LN2-002"
                        },
                        "temperatureValue": {
                            "type": "number",
                            "label": "Temperature Value",
                            "required": true,
                            "min": -200,
                            "max": 50
                        },
                        "temperatureUnit": {
                            "type": "choice",
                            "label": "Unit",
                            "options": ["C", "F"],
                            "default": "C",
                            "required": true
                        },
                        "checkTime": {
                            "type": "choice",
                            "label": "Check Time",
                            "options": ["AM", "PM"],
                            "required": true
                        },
                        "checkedBy": {
                            "type": "text",
                            "label": "Checked By",
                            "required": false
                        },
                        "checkedDateTime": {
                            "type": "dateTime",
                            "label": "Checked Date/Time",
                            "required": false
                        },
                        "notes": {
                            "type": "text",
                            "label": "Notes",
                            "multiline": true,
                            "required": false
                        }
                    }
                },
                "temperatureRanges": {
                    "Refrigerator": { "min": 2, "max": 8 },
                    "Freezer-20": { "min": -25, "max": -15 },
                    "Freezer-80": { "min": -85, "max": -75 },
                    "LN2Tank": { "min": -200, "max": -180 },
                    "Incubator": { "min": 35, "max": 38 },
                    "ColdRoom": { "min": 2, "max": 8 }
                },
                "systemActions": [
                    "Record temperature logs for environmental compliance",
                    "Display historical temperature logs in data table",
                    "Flag out-of-range temperatures with warning"
                ],
                "note": "This page is independent of sample workflow - no sample routing"
            }
